import{_ as t,o,c as a,a8 as n}from"./chunks/framework.DvHWw5tv.js";const m=JSON.parse('{"title":"useOverallComputed","description":"","frontmatter":{},"headers":[],"relativePath":"en/design/hooks/useOverall.md","filePath":"en/design/hooks/useOverall.md"}'),s={name:"en/design/hooks/useOverall.md"};function i(r,e,d,l,c,u){return o(),a("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776104037000"},[...e[0]||(e[0]=[n('<h1 id="useoverallcomputed" tabindex="-1">useOverallComputed <a class="header-anchor" href="#useoverallcomputed" aria-label="Permalink to “useOverallComputed”">​</a></h1><h3 id="useoverallcomputed-layout-and-container-overall-computation-hooks" tabindex="-1">useOverallComputed: Layout and Container Overall Computation Hooks <a class="header-anchor" href="#useoverallcomputed-layout-and-container-overall-computation-hooks" aria-label="Permalink to “useOverallComputed: Layout and Container Overall Computation Hooks”">​</a></h3><h2 id="pain-points" tabindex="-1">Pain Points <a class="header-anchor" href="#pain-points" aria-label="Permalink to “Pain Points”">​</a></h2><p>Layout systems (Layout / Row / Col) and container systems (Container / Header / Main / Aside / Footer) are the most fundamental structural components in a component library, yet they often come with massive repetitive class name and style computation logic:</p><ul><li>Need to generate numerous modifier classes based on props like <code>gutter</code>, <code>justify</code>, <code>span</code>, <code>offset</code>, <code>push/pull</code></li><li>Containers must support layout properties like <code>fixed</code> and <code>position</code>, while handling fixed positioning of header/footer</li><li>Grid system requires precise conversion of numeric props to CSS variables (e.g., <code>calc(span / 24 * 100%)</code>)</li><li>Width, height, background, and other dimensional styles require unified unit handling and CSS variable injection</li><li>Each sub-region (e.g., header, main) requires independent class names and potential state classes</li></ul><p>Implementing this logic separately in each layout component leads to highly redundant code, inconsistent naming, and difficult-to-maintain style variables.</p><h2 id="design-goals" tabindex="-1">Design Goals <a class="header-anchor" href="#design-goals" aria-label="Permalink to “Design Goals”">​</a></h2><p>This file centrally encapsulates <strong>overall class name and style computation logic</strong> for layout and container components. By reusing existing <code>useClassComputed</code> and <code>useStyleComputed</code>, it provides highly consistent, configurable computation solutions, making the implementation of Layout and Container series components extremely minimal and standardized.</p><h2 id="core-hooks-composition" tabindex="-1">Core Hooks Composition <a class="header-anchor" href="#core-hooks-composition" aria-label="Permalink to “Core Hooks Composition”">​</a></h2><table tabindex="0"><thead><tr><th>Hook</th><th>Responsibility</th><th>Applicable Components</th></tr></thead><tbody><tr><td><strong>useContainerOverAllComputed</strong></td><td>Computes class names for Container and its regions (header/main/aside/footer)</td><td>Container, Header, Main, etc.</td></tr><tr><td><strong>useContainerStyle</strong></td><td>Computes inline styles and CSS variables for Container dimensions, background, etc.</td><td>Container</td></tr><tr><td><strong>useLayoutOverAllComputed</strong></td><td>Simultaneously computes class names and styles for Row and Col (including grid variable calculation)</td><td>Row, Col (often used together)</td></tr></tbody></table><h2 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to “Core Features”">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Description</th></tr></thead><tbody><tr><td><strong>Deep Reuse of Generic Hooks</strong></td><td>Fully based on <code>useClassComputed</code> and <code>useStyleComputed</code>, maintaining logical consistency</td></tr><tr><td><strong>Precise Class Name Generation</strong></td><td>Supports BEM <code>--modifier</code> format, automatically handling flag and prop-value classes</td></tr><tr><td><strong>Intelligent CSS Variable Injection</strong></td><td>Automatically handles units (number → px), <code>calc</code> computations (grid percentages, offset, push/pull)</td></tr><tr><td><strong>Full Grid System Support</strong></td><td>Accurately implements all 24-grid properties: <code>span</code>, <code>offset</code>, <code>pull</code>, <code>push</code></td></tr><tr><td><strong>Container Layout Flexibility</strong></td><td>Supports <code>fixed</code> positioning, <code>position-right</code> layout, and other common requirements</td></tr><tr><td><strong>Type-Safe Composition</strong></td><td>Uses interface merging (<code>CombinedProps</code>) to unify handling of Row and Col props</td></tr><tr><td><strong>Zero Redundancy Design</strong></td><td>All repetitive logic is centralized here; components simply call and bind the return values</td></tr></tbody></table><h2 id="design-value" tabindex="-1">Design Value <a class="header-anchor" href="#design-value" aria-label="Permalink to “Design Value”">​</a></h2><p>These Hooks centrally manage the most tedious aspects of layout systems—class name explosion and style variable computation—ensuring:</p><ul><li>Highly unified visual and behavioral consistency across all layout components</li><li>Precise, deviation-free grid calculations</li><li>Standardized injection of CSS variables for easy theme overrides and dynamic adjustments</li><li>Extremely lean component code (only responsible for structure and slots)</li><li>Ease of future extension (e.g., responsive breakpoints, more justify modes)</li></ul>',15)])])}const h=t(s,[["render",i]]);export{m as __pageData,h as default};
